1	// Claude Code StatusLine — real-time context + cost display
2	const data = JSON.parse(require("fs").readFileSync(0, "utf8"));
3	const pct = data.context_window?.used_percentage ?? 0;
4	const model = data.model?.display_name ?? "";
5	const cost = data.cost?.total_cost_usd ?? 0;
6	
7	const barLen = 10;
8	const filled = Math.round((pct / 100) * barLen);
9	const bar = "█".repeat(filled) + "░".repeat(barLen - filled);
10	
11	let color;
12	if (pct > 75) color = "\x1b[31m";       // red
13	else if (pct > 50) color = "\x1b[33m";  // yellow
14	else color = "\x1b[32m";                 // green
15	
16	process.stdout.write(`${color}${bar}\x1b[0m ${pct.toFixed(1)}%  |  ${model}  |  $${cost.toFixed(2)}`);
