1	// PostToolUse hook: 配置文件修改后自动同步到 OB
2	const fs = require('fs');
3	const path = require('path');
4	
5	const OB_BASE = 'E:/道友的宝贝/道友的宝贝/对话归档/CC/CC配置备份';
6	
7	const RULES = [
8	  {
9	    match: (p) => p.includes('/Administrator/.claude/') && !p.includes('/projects/'),
10	    dest: '全局',
11	    files: ['CLAUDE.md', 'settings.json', 'settings.local.json', '.mcp.json']
12	  },
13	  {
14	    match: (p) => p.includes('/ClaudeWorkspace/.claude/'),
15	    dest: '项目',
16	    files: ['CLAUDE.md', 'settings.json', 'settings.local.json', 'operations-rules.md', '.mcp.json']
17	  }
18	];
19	
20	const filePath = process.env.FILE_PATH || '';
21	if (!filePath) process.exit(0);
22	
23	const fileName = path.basename(filePath);
24	const relativePath = filePath.replace(/^.*[\\/]\.claude[\\/]/, '');
25	
26	for (const rule of RULES) {
27	  if (!rule.match(filePath)) continue;
28	
29	  const destDir = path.join(OB_BASE, rule.dest);
30	  fs.mkdirSync(destDir, { recursive: true });
31	
32	  if (rule.files.includes(fileName)) {
33	    fs.copyFileSync(filePath, path.join(destDir, fileName));
34	    process.stderr.write(`[SyncHook] ${fileName} → ${rule.dest}/\n`);
35	    break;
36	  }
37	
38	  if (relativePath.startsWith('hooks/')) {
39	    const hookDestDir = path.join(destDir, 'hooks');
40	    fs.mkdirSync(hookDestDir, { recursive: true });
41	    fs.copyFileSync(filePath, path.join(hookDestDir, path.basename(fileName)));
42	    process.stderr.write(`[SyncHook] hooks/${fileName} → ${rule.dest}/hooks/\n`);
43	    break;
44	  }
45	}
